import{_ as o,o as r,c as a,a2 as p}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"算电协同的\\"不可能三角\\"","description":"","frontmatter":{},"headers":[],"relativePath":"算电协同/算电协同不可能三角.md","filePath":"算电协同/算电协同不可能三角.md","lastUpdated":1782178077000}'),n={name:"算电协同/算电协同不可能三角.md"};function e(s,t,u,l,i,q){return r(),a("div",null,[...t[0]||(t[0]=[p('<h1 id="算电协同的-不可能三角" tabindex="-1">算电协同的&quot;不可能三角&quot; <a class="header-anchor" href="#算电协同的-不可能三角" aria-label="Permalink to &quot;算电协同的&quot;不可能三角&quot;&quot;">​</a></h1><blockquote><p>道雷说道 · 第8篇</p></blockquote><hr><p>上个月四部门发《行动方案》，翻到专家解读那一页时我停住了。</p><p>国家数据发展研究院的副院长袁军，说了句大白话：算电协同面临安全、绿色、经济三重目标的协同困境——<strong>&quot;不可能三角&quot;</strong>。</p><p>让我停下来的，不是这句话本身。而是&quot;不可能三角&quot;这四个字，比过去一年我读过的所有政策文件都更诚实。它告诉你，这件事没那么简单。</p><p>政策喊得很响。但真落到投资上，你得回答一个问题：<strong>这个三角，谁在解？谁只是假装在解？</strong></p><hr><h2 id="先拆开看" tabindex="-1">先拆开看 <a class="header-anchor" href="#先拆开看" aria-label="Permalink to &quot;先拆开看&quot;">​</a></h2><p>安全、绿色、经济——三个角，分别对应三种不同的利益诉求。</p><p><strong>安全角</strong>：数据中心不能断电。一个千P智算中心停电10分钟，损失的是几百万的算力租赁收入，是正在训了三个月的模型断点。电网侧要稳定，数据中心侧要可靠，这是底线——没有商量余地。</p><p><strong>绿色角</strong>：政策定的红线——新建算力设施绿电占比不低于80%。&quot;双碳&quot;目标压着，地方政府盯着，上市公司ESG报告要写。但风光靠天吃饭，数据中心又不能等风来。</p><p><strong>经济角</strong>：电费占数据中心运营成本30-60%。企业要赚钱，不可能为了绿电让成本翻倍。四部门的文件里写的是&quot;高效经济协同&quot;，说白了就是——不能太贵。</p><p>三个角，每一个单独看都合理。合在一起就拧巴了。</p><p>打个比方：你跟朋友合伙开餐厅。<strong>安全</strong>是必须保证食材不断供，<strong>绿色</strong>是只用有机菜，<strong>经济</strong>是人均不能超过50。你试试能不能同时做到。</p><hr><h2 id="目前看到的解法" tabindex="-1">目前看到的解法 <a class="header-anchor" href="#目前看到的解法" aria-label="Permalink to &quot;目前看到的解法&quot;">​</a></h2><p>我看了几个月下来，发现大部分玩家都是在三个角里选两个来解。</p><p><strong>第一类：先保安全+经济，绿电往后放。</strong></p><p>典型的是东部存量数据中心。它们靠近需求侧，电网稳定，但绿电比例低。应对方式是买绿证——花点小钱买个&quot;名分&quot;，实际用的还是火电。这事能做，但长期看风险不小：80%绿电占比是硬约束，不是口号。2025年底的政策已经写得清楚，绿证买得再多，也不能完全替代实际消纳。</p><p><strong>第二类：先保安全+绿色，接受高成本。</strong></p><p>典型是西部的源网荷储一体化项目——大唐中卫、乌兰察布中金数据。自建风光储，绿电占比高，但综合电价并不低。我那篇文章里算过——西部风电直供数据中心的理论最低电价是0.258元/度，但甘肃现货市场电价最低到过0.145元/度。差价就是绿电直连的&quot;经济性劣势&quot;。</p><p>所以这些项目目前要么靠政策优惠（输配电费减免、容量电价补偿），要么靠示范项目光环。脱离了政策补贴，经济账还没完全跑通。</p><p><strong>第三类：今天还没看到谁真正解了三角。</strong></p><p>有一个数据值得琢磨：优刻得乌兰察布项目的毛利率是62.7%，远高于公司整体18.86%——说明西部绿电智算中心确实能赚钱。但这62.7%的毛利率，包括了绿电直连的优惠电价、当地政府补贴、以及算力租赁本身的溢价。拆开看，哪些是算电协同带来的，哪些是政策红利，哪些是算力市场本身供不应求——我没有能力完全分清楚。</p><hr><h2 id="有一个角我在盯着" tabindex="-1">有一个角我在盯着 <a class="header-anchor" href="#有一个角我在盯着" aria-label="Permalink to &quot;有一个角我在盯着&quot;">​</a></h2><p>三种解法看下来，有一个方向让我觉得最有意思——<strong>让数据中心从刚性负荷变成柔性资源</strong>。</p><p>如果数据中心能根据电价信号和绿电出力情况，灵活调节自己的算力负载，那三个角就同时被触动了：</p><ul><li><strong>安全</strong>：参与电网调峰调频，从&quot;电老虎&quot;变成电网的调峰伙伴——反而增强了系统安全</li><li><strong>绿色</strong>：绿电多的时候多用，绿电少的时候少用——自然提高绿电消纳比例</li><li><strong>经济</strong>：低谷电价时多算，高峰电价时少算（或转去西部）——省电费，甚至还能赚需求响应的钱</li></ul><p>这不是理论。2026年5月广东已经做了数据中心VPP现货交易首单。安徽电信更直接——把合肥智算中心的算力任务平稳转移到淮北中心，3分钟切换完成，单机用电负荷上升50%，消纳了当地的绿电。</p><h3 id="但有一个问题我还没想明白" tabindex="-1">但有一个问题我还没想明白 <a class="header-anchor" href="#但有一个问题我还没想明白" aria-label="Permalink to &quot;但有一个问题我还没想明白&quot;">​</a></h3><p>柔性调节这个逻辑，最大的应用场景是<strong>推理</strong>，不是训练。</p><p>训练任务可以中断、可以迁移、可以夜间跑——本来就是柔性的。但推理是实时的、不可中断的、对延迟有刚性要求的。你刷抖音、用ChatGPT、调用AI Agent，这些都是推理。它们不能等绿电来了再返回结果。</p><p>所以&quot;算力柔性调节&quot;更适合的是：</p><ul><li>数据备份、批量处理任务 ✅</li><li>AI训练任务（non-real-time） ✅</li><li>AI推理（real-time） ❌</li></ul><p>而推理才是未来算力需求的大头——国家数据局的数据显示，2025年推理数据量首次超过训练，未来推理与训练的需求比可能达到3:1。</p><p>这意味着什么？意味着<strong>大部分新增的算力需求，恰恰是那个&quot;不能等电&quot;的部分</strong>。如果推理算力不能柔性调节，那算电协同的&quot;不可能三角&quot;在最大的增量市场上，还是解不开。</p><hr><h2 id="我的判断" tabindex="-1">我的判断 <a class="header-anchor" href="#我的判断" aria-label="Permalink to &quot;我的判断&quot;">​</a></h2><p>如果要给一个不骑墙的结论：</p><p><strong>短期（1-2年）</strong>，政策红利和示范效应会催生一批项目。做需求响应聚合平台、AI制冷优化SaaS的公司最值得关注——轻资产、高壁垒、吃到了算电协同的第一波红利却不背重资产的锅。</p><p><strong>中期（3-5年）</strong>，&quot;不可能三角&quot;的真正解法可能不出现在单一公司层面，而是整个电力市场化改革和算力调度体系的重构。换句话说，不是某一个技术突破，而是制度突破——全国统一电力市场建成，绿电跨省交易打通，算力调度平台实现全国&quot;一张网&quot;。</p><p><strong>长期来看</strong>，我不确定的是推理算力的&quot;柔性化&quot;能不能被技术突破。但我确定的是：<strong>算电协同的&quot;不可能三角&quot;里，谁先解开了绿色和经济的矛盾，谁就是这个时代最大的赢家。</strong></p><p>因为安全这个角，反倒是最容易的——钱到位了，备电做到位了，它就是确定性最高的那个角。</p><hr><p><em>以上是我个人的判断，我可能是错的。尤其是那个推理不能柔性的判断，如果液冷+储能+微电网的组合能把推理机房的PUE做到1.05以下、绿电占比做到80%以上，那我的逻辑需要重新推。</em></p><p><em>欢迎留言讨论。</em></p><hr><p><em>创作于 2026-06-23 · 道雷说道</em></p>',50)])])}const d=o(n,[["render",e]]);export{h as __pageData,d as default};
